import{_ as o,c as e,o as a,ag as p}from"./chunks/framework.ELrfyV9R.js";const l=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"ai/2026-03/harness.md","filePath":"ai/2026-03/harness.md","lastUpdated":1775818659000}'),r={name:"ai/2026-03/harness.md"};function s(n,t,u,_,A,i){return a(),e("div",null,t[0]||(t[0]=[p("<p>Harness：让 AI Agent 系统稳定运行的五层架构</p><p>环境层（Environment）</p><p>是整个系统的地基，解决的是&quot;AI 活在哪里&quot;的问题。它为 AI 提供一个安全、受控的工作空间，让 AI 能够读写文件、操作数据库、执行代码和终端命令。简单说，就是给 AI 搭一个真实可用的&quot;操作台&quot;，既能触达真实世界，又不会失控乱跑。</p><p>工具层（Tool）</p><p>解决的是&quot;AI 怎么动手&quot;的问题。真实世界的系统往往很复杂，工具层的职责就是把这些复杂逻辑封装成简单、清晰的函数接口，比如 readFile、runTest、callAPI。AI 不需要知道底层怎么实现，只管调用就好——接口越简单，AI 出错的概率就越低，行动也越果断。</p><p>控制层（Control）</p><p>是系统的&quot;安全护栏&quot;，解决的是&quot;谁来管着 AI&quot;的问题。它统筹整个任务流程，设定最大执行步数防止死循环，设定超时时间防止任务拖而不决，控制工具调用频率防止资源滥用，还要在出现异常时兜底处理。没有控制层，AI 一旦走偏，整个系统就会失控。</p><p>记忆层（Memory）</p><p>解决的是&quot;AI 怎么记住事情&quot;的问题。AI 的上下文窗口是有限的，只靠短期记忆根本撑不住复杂任务。记忆层负责把任务状态、历史步骤、关键决策沉淀下来，过滤后存入长期存储，让 AI 在任务推进过程中始终知道&quot;自己做到哪了、之前决定了什么&quot;，而不是每次都从零开始。</p><p>评估层（Evaluation）</p><p>是系统的质量关口，解决的是&quot;结果对不对谁来判&quot;的问题。AI 生成的输出不会被直接采纳，而是先进入自动测试流程：通过了，才算完成；没通过，把错误信息反馈给模型，让它继续修。这形成了一个完整的闭环——模型负责生成，评估层负责验收，整个过程自动运转，不依赖人工逐一检查。</p>",11)]))}const q=o(r,[["render",s]]);export{l as __pageData,q as default};
